import{_ as e,o as d,c as a,ak as o}from"./chunks/framework.Cv89Y5zG.js";const p=JSON.parse('{"title":"Decision tree","description":"","frontmatter":{},"headers":[],"relativePath":"next/ai/decision-tree.md","filePath":"next/ai/decision-tree.md","lastUpdated":1777100574000}'),r={name:"next/ai/decision-tree.md"};function c(s,t,i,n,l,h){return d(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="decision-tree" tabindex="-1">Decision tree <a class="header-anchor" href="#decision-tree" aria-label="Permalink to “Decision tree”">​</a></h1><p>Which API to reach for, by task. Tables, not prose. If your question isn&#39;t answered below, it&#39;s either not a common task or you need the full <a href="./../guide/introduction">Guide</a>.</p><h2 id="i-want-to-mock-x-→-which-factory" tabindex="-1">&quot;I want to mock X&quot; → which factory? <a class="header-anchor" href="#i-want-to-mock-x-→-which-factory" aria-label="Permalink to “&quot;I want to mock X&quot; → which factory?”">​</a></h2><table tabindex="0"><thead><tr><th>What you have</th><th>Factory</th><th>Example</th></tr></thead><tbody><tr><td>A TypeScript interface or type, no instance</td><td><code>stub&lt;T&gt;([&#39;method1&#39;, &#39;method2&#39;])</code></td><td><code>stub&lt;Database&gt;([&#39;query&#39;])</code></td></tr><tr><td>An existing object instance</td><td><code>stub(obj)</code></td><td><code>stub(new Logger())</code></td></tr><tr><td>A class (want prototype methods auto-discovered)</td><td><code>stub(MyClass)</code></td><td><code>stub(Greeter)</code></td></tr><tr><td>A class (want static methods instead)</td><td><code>stub(MyClass, undefined, { debug:{prefix:&#39;deride&#39;,suffix:&#39;stub&#39;}, static:true })</code></td><td><code>stub(Greeter, undefined, {…, static:true})</code></td></tr><tr><td>Code that does <code>new MyClass(...)</code> somewhere and you want to intercept</td><td><code>stub.class(MyClass)</code></td><td><code>stub.class(Database)</code></td></tr><tr><td>An existing object where <strong>real methods should run by default</strong></td><td><code>wrap(obj)</code></td><td><code>wrap(realLogger)</code></td></tr><tr><td>An existing standalone function</td><td><code>wrap(fn)</code> or <code>func(fn)</code> (identical)</td><td><code>wrap(handler)</code></td></tr><tr><td>A brand-new standalone function from scratch</td><td><code>func&lt;F&gt;()</code></td><td><code>func&lt;(x: number) =&gt; number&gt;()</code></td></tr></tbody></table><p><strong>Rules of thumb:</strong></p><ul><li><code>stub</code> replaces, <code>wrap</code> preserves real behaviour until overridden.</li><li><code>stub.class</code> is only for <code>new</code>-call interception. If you control the call site, inject a <code>stub(...)</code> instance instead.</li><li>Use <code>func()</code> when the dependency is <strong>itself</strong> a function (callback, handler, fetcher).</li></ul><h2 id="i-want-the-method-to-return-x-→-which-setup" tabindex="-1">&quot;I want the method to return X&quot; → which setup? <a class="header-anchor" href="#i-want-the-method-to-return-x-→-which-setup" aria-label="Permalink to “&quot;I want the method to return X&quot; → which setup?”">​</a></h2><table tabindex="0"><thead><tr><th>Behaviour</th><th>Setup</th></tr></thead><tbody><tr><td>Return a fixed value</td><td><code>.toReturn(value)</code> (use <code>.toReturn&lt;T&gt;(value)</code> if the method&#39;s return type collapses to <code>void</code> — see <a href="./common-mistakes#_12-fighting-setup-methods-when-the-inferred-return-type-is-void">common mistake #12</a>)</td></tr><tr><td>Return the mock itself (fluent APIs)</td><td><code>.toReturnSelf()</code></td></tr><tr><td>Run custom logic with access to args</td><td><code>.toDoThis((a, b) =&gt; …)</code></td></tr><tr><td>Throw an Error(msg)</td><td><code>.toThrow(message)</code></td></tr><tr><td>Return a resolved Promise with a value</td><td><code>.toResolveWith(value)</code> (use <code>.toResolveWith&lt;T&gt;(value)</code> if the method&#39;s return type collapses to <code>void</code> — see <a href="./common-mistakes#_12-fighting-setup-methods-when-the-inferred-return-type-is-void">common mistake #12</a>)</td></tr><tr><td>Return a resolved Promise with no value</td><td><code>.toResolve()</code></td></tr><tr><td>Return a rejected Promise</td><td><code>.toRejectWith(error)</code></td></tr><tr><td>Resolve after N ms (use with fake timers)</td><td><code>.toResolveAfter(ms, value)</code></td></tr><tr><td>Reject after N ms</td><td><code>.toRejectAfter(ms, error)</code></td></tr><tr><td>Return a Promise that never settles</td><td><code>.toHang()</code></td></tr><tr><td>Return each value in a sequence (sticky-last)</td><td><code>.toReturnInOrder(a, b, c)</code></td></tr><tr><td>Same for promises</td><td><code>.toResolveInOrder(…)</code> / <code>.toRejectInOrder(…)</code></td></tr><tr><td>Return a fresh sync iterator</td><td><code>.toYield(1, 2, 3)</code></td></tr><tr><td>Return a fresh async iterator</td><td><code>.toAsyncYield(1, 2, 3)</code></td></tr><tr><td>Async iterator that throws partway</td><td><code>.toAsyncYieldThrow(err, v1, v2)</code></td></tr><tr><td>Invoke the last callback argument</td><td><code>.toCallbackWith(err, data)</code></td></tr><tr><td>Emit an event on the wrapped object</td><td><code>.toEmit(eventName, …args)</code></td></tr><tr><td>Run a side-effect then run the real method</td><td><code>.toIntercept((…args) =&gt; { … })</code></td></tr><tr><td>Accelerate a callback-based timeout</td><td><code>.toTimeWarp(ms)</code></td></tr><tr><td>Clear all configured behaviours</td><td><code>.fallback()</code></td></tr></tbody></table><h2 id="i-want-to-gate-a-behaviour-→-which-modifier" tabindex="-1">&quot;I want to gate a behaviour&quot; → which modifier? <a class="header-anchor" href="#i-want-to-gate-a-behaviour-→-which-modifier" aria-label="Permalink to “&quot;I want to gate a behaviour&quot; → which modifier?”">​</a></h2><table tabindex="0"><thead><tr><th>Condition</th><th>Modifier (chain BEFORE the behaviour)</th></tr></thead><tbody><tr><td>Only when first arg equals X</td><td><code>.when(X)</code></td></tr><tr><td>Only when first arg passes matcher</td><td><code>.when(match.string)</code></td></tr><tr><td>Only when multiple positional args match</td><td><code>.when(match.string, match.number)</code></td></tr><tr><td>Only when custom predicate on args returns true</td><td><code>.when((args) =&gt; …)</code></td></tr><tr><td>Only the next call</td><td><code>.once()</code></td></tr><tr><td>Only the next 2 calls</td><td><code>.twice()</code></td></tr><tr><td>Only the next N calls</td><td><code>.times(n)</code></td></tr></tbody></table><p>Chain multiple behaviours in sequence:</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mock.setup.greet</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">when</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;alice&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">toReturn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;hi alice&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">once</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  .and.then</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">toReturn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;default&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="i-want-to-match-an-argument-→-which-matcher" tabindex="-1">&quot;I want to match an argument&quot; → which matcher? <a class="header-anchor" href="#i-want-to-match-an-argument-→-which-matcher" aria-label="Permalink to “&quot;I want to match an argument&quot; → which matcher?”">​</a></h2><p>Import from <code>deride</code>: <code>import { match } from &#39;deride&#39;</code></p><table tabindex="0"><thead><tr><th>Assertion</th><th>Matcher</th></tr></thead><tbody><tr><td>Any value, including nullish</td><td><code>match.any</code></td></tr><tr><td>Not undefined (null OK)</td><td><code>match.defined</code></td></tr><tr><td>Exactly null or undefined</td><td><code>match.nullish</code></td></tr><tr><td>typeof string / number / boolean / bigint / symbol / function</td><td><code>match.string</code> / <code>match.number</code> / etc.</td></tr><tr><td>Is an array</td><td><code>match.array</code></td></tr><tr><td>Is a plain object (non-null, non-array)</td><td><code>match.object</code></td></tr><tr><td><code>instanceof</code> some class</td><td><code>match.instanceOf(Ctor)</code></td></tr><tr><td>Object containing these keys with these values (matcher-aware)</td><td><code>match.objectContaining({ id: match.number })</code></td></tr><tr><td>Array containing these items (any order)</td><td><code>match.arrayContaining([1, 2])</code></td></tr><tr><td>Strict deep equal, no extra keys</td><td><code>match.exact(value)</code></td></tr><tr><td>Number / bigint &gt; &lt; &gt;= &lt;=</td><td><code>match.gt(n)</code> / <code>match.gte(n)</code> / <code>match.lt(n)</code> / <code>match.lte(n)</code></td></tr><tr><td>Number / bigint in range, inclusive</td><td><code>match.between(low, high)</code></td></tr><tr><td>String matches regex</td><td><code>match.regex(/pattern/)</code></td></tr><tr><td>String starts/ends/includes</td><td><code>match.startsWith(s)</code> / <code>match.endsWith(s)</code> / <code>match.includes(s)</code></td></tr><tr><td>NOT matching m</td><td><code>match.not(m)</code></td></tr><tr><td>ALL of (m1, m2, …)</td><td><code>match.allOf(m1, m2)</code></td></tr><tr><td>AT LEAST ONE of matcher list</td><td><code>match.oneOf(m1, m2)</code></td></tr><tr><td>Equal to OR matches any of these values</td><td><code>match.anyOf(v1, v2, …)</code></td></tr><tr><td>Custom predicate, named</td><td><code>match.where(v =&gt; …, &#39;description&#39;)</code></td></tr></tbody></table><p>Matchers compose and nest — use them inside <code>objectContaining</code>, <code>arrayContaining</code>, <code>exact</code>, or anywhere a value goes.</p><h2 id="i-want-to-assert-how-it-was-called-→-which-expect" tabindex="-1">&quot;I want to assert how it was called&quot; → which expect? <a class="header-anchor" href="#i-want-to-assert-how-it-was-called-→-which-expect" aria-label="Permalink to “&quot;I want to assert how it was called&quot; → which expect?”">​</a></h2><table tabindex="0"><thead><tr><th>Question</th><th>Assertion</th></tr></thead><tbody><tr><td>Was it called exactly N times?</td><td><code>.called.times(n)</code> / <code>.once()</code> / <code>.twice()</code> / <code>.never()</code></td></tr><tr><td>Call count &lt; / &lt;= / &gt; / &gt;= N</td><td><code>.called.lt(n)</code> / <code>.lte(n)</code> / <code>.gt(n)</code> / <code>.gte(n)</code></td></tr><tr><td>Any call had this arg (partial deep match)</td><td><code>.called.withArg(arg)</code></td></tr><tr><td>Any call had these args (all present)</td><td><code>.called.withArgs(a, b)</code></td></tr><tr><td>Any call&#39;s args matched a regex (deep)</td><td><code>.called.withMatch(/regex/)</code></td></tr><tr><td>Any call had EXACTLY these args (strict deep equal)</td><td><code>.called.matchExactly(a, b)</code></td></tr><tr><td>Any call returned this value (or matcher)</td><td><code>.called.withReturn(value)</code></td></tr><tr><td>Any call was made on this <code>this</code></td><td><code>.called.calledOn(target)</code></td></tr><tr><td>Any call threw (optional: Error message / class / matcher)</td><td><code>.called.threw(expected?)</code></td></tr><tr><td>The i-th call included this arg</td><td><code>.invocation(i).withArg(arg)</code></td></tr><tr><td>EVERY call matched (each of the above)</td><td><code>.everyCall.withArg(…)</code> etc.</td></tr><tr><td>Negate any of the above</td><td><code>.called.not.withArg(...)</code></td></tr></tbody></table><p><strong>Decision rule:</strong> if you want a test to fail when the assertion fails, use <code>expect.called.*</code>. If you want a boolean / data / to branch, use <code>spy.*</code>.</p><h2 id="i-want-to-read-call-history-→-spy-surface" tabindex="-1">&quot;I want to read call history&quot; → spy surface <a class="header-anchor" href="#i-want-to-read-call-history-→-spy-surface" aria-label="Permalink to “&quot;I want to read call history&quot; → spy surface”">​</a></h2><table tabindex="0"><thead><tr><th>Need</th><th>Reach for</th></tr></thead><tbody><tr><td>&quot;Was it called with X?&quot; as a boolean</td><td><code>mock.spy.method.calledWith(x)</code></td></tr><tr><td>Total call count</td><td><code>mock.spy.method.callCount</code></td></tr><tr><td>All recorded calls</td><td><code>mock.spy.method.calls</code></td></tr><tr><td>First / last recorded call</td><td><code>mock.spy.method.firstCall</code> / <code>lastCall</code></td></tr><tr><td>A captured return value</td><td><code>mock.spy.method.lastCall?.returned</code></td></tr><tr><td>A captured <code>this</code> binding</td><td><code>mock.spy.method.lastCall?.thisArg</code></td></tr><tr><td>A captured sync throw</td><td><code>mock.spy.method.lastCall?.threw</code></td></tr><tr><td>Pretty-print the full call log for debugging</td><td><code>mock.spy.method.printHistory()</code></td></tr><tr><td>Stable snapshot-friendly dump</td><td><code>mock.spy.method.serialize()</code></td></tr></tbody></table><p>For async return values, <code>lastCall.returned</code> is the Promise. <code>await</code> it to get the settled value.</p><h2 id="i-need-to-assert-cross-mock-ordering-→-inorder" tabindex="-1">&quot;I need to assert cross-mock ordering&quot; → inOrder <a class="header-anchor" href="#i-need-to-assert-cross-mock-ordering-→-inorder" aria-label="Permalink to “&quot;I need to assert cross-mock ordering&quot; → inOrder”">​</a></h2><table tabindex="0"><thead><tr><th>Need</th><th>Reach for</th></tr></thead><tbody><tr><td>Assert spies fired in this order (first call of each)</td><td><code>inOrder(a.spy.x, b.spy.y, c.spy.z)</code></td></tr><tr><td>Order a specific invocation of a spy</td><td><code>inOrder(inOrder.at(a.spy.x, 0), b.spy.y)</code></td></tr><tr><td>Strict: no extra calls on listed spies between</td><td><code>inOrder.strict(a.spy.x, b.spy.y)</code></td></tr></tbody></table><h2 id="i-need-test-lifecycle-helpers-→-sandbox-snapshot" tabindex="-1">&quot;I need test lifecycle helpers&quot; → sandbox / snapshot <a class="header-anchor" href="#i-need-test-lifecycle-helpers-→-sandbox-snapshot" aria-label="Permalink to “&quot;I need test lifecycle helpers&quot; → sandbox / snapshot”">​</a></h2><table tabindex="0"><thead><tr><th>Need</th><th>Reach for</th></tr></thead><tbody><tr><td>Reset call history on every mock between tests</td><td><code>sandbox().reset()</code> in <code>afterEach</code></td></tr><tr><td>Full wipe (history + behaviours)</td><td><code>sandbox().restore()</code> in <code>afterAll</code></td></tr><tr><td>Save/restore a single mock&#39;s state mid-test</td><td><code>mock.snapshot()</code> / <code>mock.restore(snap)</code></td></tr><tr><td>Reset ONE mock&#39;s history</td><td><code>mock.called.reset()</code></td></tr></tbody></table><h2 id="i-need-fake-timers-→-deride-clock" tabindex="-1">&quot;I need fake timers&quot; → deride/clock <a class="header-anchor" href="#i-need-fake-timers-→-deride-clock" aria-label="Permalink to “&quot;I need fake timers&quot; → deride/clock”">​</a></h2><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { useFakeTimers, isFakeTimersActive, restoreActiveClock } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;deride/clock&#39;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Need</th><th>Reach for</th></tr></thead><tbody><tr><td>Install fake Date / setTimeout / setInterval / queueMicrotask</td><td><code>const clock = useFakeTimers()</code></td></tr><tr><td>Advance time by N ms and fire due timers</td><td><code>clock.tick(ms)</code></td></tr><tr><td>Drain all pending timers</td><td><code>clock.runAll()</code> (throws if setInterval would loop)</td></tr><tr><td>Drain microtasks</td><td><code>clock.flushMicrotasks()</code></td></tr><tr><td>Read captured callback errors</td><td><code>clock.errors</code></td></tr><tr><td>Restore native globals</td><td><code>clock.restore()</code></td></tr><tr><td>Safety net in <code>afterEach</code></td><td><code>if (isFakeTimersActive()) restoreActiveClock()</code></td></tr></tbody></table><h2 id="i-need-framework-matchers-→-deride-vitest-or-deride-jest" tabindex="-1">&quot;I need framework matchers&quot; → deride/vitest or deride/jest <a class="header-anchor" href="#i-need-framework-matchers-→-deride-vitest-or-deride-jest" aria-label="Permalink to “&quot;I need framework matchers&quot; → deride/vitest or deride/jest”">​</a></h2><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;deride/vitest&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // or &#39;deride/jest&#39; — side-effect import, registers matchers</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Matcher</th><th>Semantics</th></tr></thead><tbody><tr><td><code>expect(mock.spy.x).toHaveBeenCalled()</code></td><td>&gt;= 1 call</td></tr><tr><td><code>.toHaveBeenCalledTimes(n)</code></td><td>exactly N</td></tr><tr><td><code>.toHaveBeenCalledOnce()</code></td><td>exactly 1</td></tr><tr><td><code>.toHaveBeenCalledWith(...args)</code></td><td>any call&#39;s args match</td></tr><tr><td><code>.toHaveBeenLastCalledWith(...args)</code></td><td>last call&#39;s args match</td></tr><tr><td><code>.toHaveBeenNthCalledWith(n, ...args)</code></td><td>n is <strong>1-indexed</strong></td></tr></tbody></table><p>Works on a <code>MethodSpy</code> (<code>mock.spy.greet</code>) or a <code>MockedFunction</code> proxy directly.</p>`,33)])])}const m=e(r,[["render",c]]);export{p as __pageData,m as default};
